#### 1. TestEvaluationResult Struct Tests (tests/unit/test_evaluation_result.rs)
```rust
#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_evaluation_result_allowed_command() {
        // Test that allowed commands have correct outcome, empty pattern matches
        let result = evaluate_test_command("git status", &config);
        assert_eq!(result.outcome, Outcome::Allow);
        assert!(result.pattern_matches.is_empty());
        assert!(result.blocking_rule.is_none());
    }

    #[test]
    fn test_evaluation_result_blocked_command() {
        // Test that blocked commands capture full match details
        let result = evaluate_test_command("rm -rf /", &config);
        assert_eq!(result.outcome, Outcome::Deny);
        assert!(!result.pattern_matches.is_empty());
        assert!(result.blocking_rule.is_some());
        assert_eq!(result.blocking_rule.unwrap().pack_id, "core.filesystem");
    }

    #[test]
    fn test_evaluation_result_allowlist_override() {
        // Test commands that WOULD match but are allowlisted
        let mut config = Config::default();
        config.allowlist.push("npm run build".to_string());
        let result = evaluate_test_command("npm run build", &config);
        assert_eq!(result.outcome, Outcome::Allow);
        assert!(result.allowlist_match.is_some());
    }

    #[test]
    fn test_evaluation_result_confidence_threshold() {
        // Test confidence scoring affects outcome
        let result = evaluate_test_command("docker rm container", &config);
        assert!(result.confidence_score >= 0.0 && result.confidence_score <= 1.0);
    }
}
```

